<section class="tech-section" id="tech">
  <div class="container">
    <div class="section-header">
      <h2 class="section-title">Built on Modern Tech</h2>
      <p class="section-sub">Small binary, fast startup, solid foundation.</p>
    </div>

    <div class="tech-grid">
      {#each stack as tech}
        <div class="tech-card" style="--brand: {tech.color}">
          <div class="tech-icon" style="color: {tech.color}">
            {@html tech.icon}
          </div>
          <div class="tech-name">{tech.name}</div>
          <div class="tech-tagline">{tech.tagline}</div>
        </div>
      {/each}
    </div>
  </div>
</section>

<style>
  .tech-section {
    padding: 80px 24px;
    background: var(--bg-base);
    position: relative;
  }

  .tech-section::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    height: 1px;
    background: linear-gradient(90deg, transparent, rgba(249,115,22,0.2), transparent);
  }

  .container {
    max-width: 900px;
    margin: 0 auto;
  }

  .section-header {
    text-align: center;
    margin-bottom: 48px;
  }

  .section-title {
    font-size: clamp(1.5rem, 3vw, 2.2rem);
    font-weight: 800;
    color: white;
    margin: 0 0 12px;
    letter-spacing: -0.5px;
  }

  .section-sub {
    font-size: 1rem;
    color: var(--text-muted);
    margin: 0;
  }

  .tech-grid {
    display: grid;
    grid-template-columns: repeat(4, 1fr);
    gap: 16px;
  }

  .tech-card {
    background: var(--bg-surface);
    border: 1px solid rgba(255,255,255,0.06);
    border-radius: 12px;
    padding: 28px 20px;
    text-align: center;
    transition: border-color 0.2s ease, box-shadow 0.2s ease, transform 0.2s ease;
  }

  .tech-card:hover {
    border-color: color-mix(in srgb, var(--brand) 60%, transparent);
    box-shadow: 0 0 24px color-mix(in srgb, var(--brand) 15%, transparent);
    transform: translateY(-3px);
  }

  .tech-icon {
    display: flex;
    justify-content: center;
    margin-bottom: 14px;
  }

  .tech-name {
    font-size: 15px;
    font-weight: 700;
    color: white;
    margin-bottom: 6px;
  }

  .tech-tagline {
    font-size: 12px;
    color: var(--text-muted);
    line-height: 1.4;
  }

  @media (max-width: 700px) {
    .tech-grid { grid-template-columns: repeat(2, 1fr); }
  }

  @media (max-width: 400px) {
    .tech-grid { grid-template-columns: 1fr; }
  }
</style>
